INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ", 27, "獣人族", 2, 44, 100101, 16, 0, "A", 155, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ", 5, "ヒューマン", 2, 47, 100201, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ", 12, "魔族", 2, 46, 100301, 18, 0, "B", 163, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "探検好きのイタズラっ子", "諸星すみれ", "ミソギ", 10, "ヒューマン", 5, 27, 100401, 9, 0, "O", 128, "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "ヒーローに憧れる騎士見習いの少女", "下田麻美", "マツリ", 25, "獣人族", 8, 40, 100501, 12, 0, "O", 146, "ヒーローごっこ", "？？？", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "甘え上手なみんなの人気者", "浅倉杏美", "アカリ", 22, "魔族", 7, 42, 100601, 13, 0, "O", 150, "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "プリン大好きゴースト娘", "雨宮天", "ミヤコ", 23, "魔族", 7, 32, 100701, 14, 0, "B", 130, "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ボクは誰よりも美しい", "大空直美", "ユキ", 10, "エルフ", 15, 40, 100801, 14, 0, "AB", 150, "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ", 5, "魔族", 13, 45, 100901, 17, 0, "A", 159, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "マホマホ王国のプリンセス", "内田真礼", "マホ", 22, "獣人族", 10, 42, 101001, 16, 0, "O", 155, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ", 25, "ヒューマン", 3, 44, 101101, 15, 0, "A", 156, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ", 24, "エルフ", 6, 46, 101201, 17, 0, "A", 156, "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "オタク全開な魔法少女", "佳村はるか", "ナナカ", 21, "魔族", 13, 55, 101301, 18, 0, "O", 166, "読書、魔法", "", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ", 3, "獣人族", 10, 41, 101401, 15, 0, "AB", 152, "読書、推理", "test", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "ミサト", 5, "エルフ", 6, 54, 101501, 21, 0, "O", 165, "絵本作り", "test", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ", 10, "魔族", 14, 48, 101601, 17, 0, "O", 167, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "カオリ", 7, "獣人族", 10, 53, 101701, 17, 0, "A", 158, "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "多くの男性を魅了する無垢な女教師", "伊藤静", "イオ", 14, "魔族", 14, 52, 101801, 23, 0, "B", 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ", 3, "獣人族", 5, 21, 102001, 10, 0, "O", 117, "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ", 9, "ヒューマン", 9, 40, 102101, 12, 0, "B", 150, "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "人見知りであまのじゃくな女の子", "原紗友里", "ヨリ", 22, "魔族", 7, 40, 102201, 13, 0, "O", 150, "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "ぷうきちといつも一緒！", "芹澤優", "アヤネ", 10, "ヒューマン", 9, 38, 102301, 14, 0, "B", 148, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ", 12, "ヒューマン", 9, 43, 102501, 15, 0, "O", 154, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "リン", 1, "獣人族", 11, 42, 102601, 17, 0, "B", 144, "あんパン", "test", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ", 30, "魔族", 13, 43, 102701, 16, 0, "B", 154, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン", 4, "エルフ", 9, 43, 102801, 17, 0, "A", 156, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "歌って踊れる大人気アイドル", "日笠陽子", "ノゾミ", 24, "ヒューマン", 4, 40, 102901, 17, 0, "B", 157, "舞台鑑賞、ダンス", "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン", 31, "ヒューマン", 15, 51, 103001, 16, 0, "O", 163, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "占いが得意な霊能少女", "大坪由佳", "シノブ", 22, "魔族", 7, 42, 103101, 18, 0, "AB", 157, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "アキノ", 12, "ヒューマン", 12, 45, 103201, 18, 0, "AB", 157, "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル", 3, "ヒューマン", 11, 35, 103301, 20, 0, "B", 142, "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "純情でほっとけない大人の女性", "今井麻美", "ユカリ", 16, "エルフ", 12, 55, 103401, 22, 0, "A", 164, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "キョウカ", 2, "エルフ", 5, 21, 103601, 8, 0, "A", 118, "お勉強", "test", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "義理堅くてからかい好きな剣術少女", "茅原実里", "トモ", 11, "ヒューマン", 8, 43, 103701, 13, 0, "A", 149, "剣術、年長者をからかう", "test", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "読書が趣味の病弱少女", "小清水亜美", "シオリ", 3, "獣人族", 11, 40, 103801, 14, 0, "A", 153, "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ", 6, "エルフ", 6, 44, 104001, 13, 0, "AB", 158, "友達作りのイメトレ", "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ", 3, "ヒューマン", 4, 46, 104201, 17, 0, "O", 163, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "男勝りで情に厚いワイルド娘", "小松未可子", "マコト", 9, "獣人族", 10, 54, 104301, 17, 0, "O", 168, "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "かつては夜を支配した最強の吸血鬼", "丹下桜", "イリヤ", 5, "魔族", 7, 50, 104401, "??", 0, "A", 172, "世界征服", "test", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ", 19, "ヒューマン", 15, 49, 104501, 18, 0, "AB", 157, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ", 1, "獣人族", 12, 48, 104601, 19, 0, "AB", 158, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン", 25, "ヒューマン", 8, 50, 104701, 25, 0, "A", 171, "格闘技、湯浴み", "？？？", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ", 11, "ヒューマン", 12, 49, 104801, 20, 0, "O", 163, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル", 24, "ヒューマン", 3, 54, 104901, 18, 0, "O", 168, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ", 3, "魔族", 14, 22, 105001, 11, 0, "A", 120, "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "実験が趣味の危険な科学者", "三石琴乃", "ミツキ", 7, "ヒューマン", 13, 53, 105101, 27, 0, "A", 166, "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "乙女チックなもふもふアニマル", "徳井青空", "リマ", 14, "獣人族", 11, 100, 105201, 17, 0, "A", 150, "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ", 28, "ヒューマン", 15, 33, 105301, 17, 0, "A", 140, "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ", 7, "ヒューマン", 4, 45, 105401, 14, 0, "AB", 153, "裁縫", "test", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ", 7, "エルフ", 15, 43, 105501, 16, 0, "O", 155, "観察", "test", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "人情味溢れる粋でいなせな「姉御」", "佐藤利奈", "ルカ", 11, "ヒューマン", 13, 54, 105601, 25, 0, "B", 167, "釣り", "test", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "空への冒険を夢見る騎空士の少女", "金元寿子", "ジータ", 10, "ヒューマン", "", 45, 105701, 17, 0, "O", 156, "冒険、おしゃべり", "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "いつも元気な腹ペコ少女", "M・A・O", "ペコリーヌ", 31, "ヒューマン", 1, 46, 105801, 17, 0, "O", 156, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ", 11, "エルフ", 1, 35, 105901, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル", 2, "獣人族", 1, 39, 106001, 14, 0, "A", 152, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "さまよえる謎の少女", "潘めぐみ", "ムイミ", 11, "ヒューマン", "", 40, 106101, 16, 0, "O", 148, "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "森番を目指すエルフの少女", "優木かな", "アリサ", 17, "エルフ", "", 42, 106301, 15, 0, "O", 155, "キレイな葉っぱを集めること", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "記憶喪失のドラゴン娘", "近藤玲奈", "シェフィ", 14, "ドラゴン族", 1, "???", 106401, 14, 0, "B", 147, "読書、ストレッチ", "", "美食殿");
