INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "口が達者なヘタレドラゴン", "藤田茜", "イノリ", 29, "ドラゴン族", 17, "???", 106601, 13, 0, "AB", 145, "ゲーム", "", "ドラゴンズネスト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "妖しい微笑で全てを見透かす臥竜の頭領", "大西沙織", "ホマレ", 17, "ドラゴン族", 17, "???", 106701, 25, 0, "O", 168, "絵画、読書", "", "ドラゴンズネスト");
