INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "謎に包まれたランドソルの主", "蒼井翔太", "カイザーインサイト", 1, "獣人族", "", "??", 106901, 29, 0, "AB", 166, "占い、支配", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "研究所に隠れ住む物静かなお姉さん", "井口裕香", "ネネカ", 24, "エルフ", "", "??", 107001, 24, 0, "O", 149, "物真似、芸術鑑賞", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "傍若無人な王宮騎士団副団長", "たかはし智秋", "クリスティーナ", 7, "ヒューマン", 8, "??", 107101, 27, 0, "O", 165, "強敵との闘争", "", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "いつも元気な腹ペコ少女", "M・A・O", "ペコリーヌ（サマー）", 31, "ヒューマン", 1, 46, 107501, 17, 0, "O", 156, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（サマー）", 11, "エルフ", 1, 35, 107601, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ（サマー）", 12, "ヒューマン", 9, 43, 107701, 15, 0, "O", 154, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（サマー）", 2, "獣人族", 1, 39, 107801, 14, 0, "A", 152, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（サマー）", 1, "獣人族", 12, 48, 107901, 19, 0, "AB", 158, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ（サマー）", 11, "ヒューマン", 12, 49, 108001, 20, 0, "O", 163, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "占いが得意な霊能少女", "大坪由佳", "シノブ（ハロウィン）", 22, "魔族", 7, 42, 108101, 18, 0, "AB", 157, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "プリン大好きゴースト娘", "雨宮天", "ミヤコ（ハロウィン）", 23, "魔族", 7, 32, 108201, 14, 0, "B", 130, "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ（ハロウィン）", 3, "魔族", 14, 22, 108301, 11, 0, "A", 120, "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ（クリスマス）", 3, "ヒューマン", 4, 46, 108401, 17, 0, "O", 163, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ（クリスマス）", 9, "ヒューマン", 9, 40, 108501, 12, 0, "B", 150, "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "ぷうきちといつも一緒！", "芹澤優", "アヤネ（クリスマス）", 10, "ヒューマン", 9, 38, 108601, 14, 0, "B", 148, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（ニューイヤー）", 27, "獣人族", 2, 44, 108701, 16, 0, "A", 155, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（ニューイヤー）", 5, "ヒューマン", 2, 47, 108801, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（ニューイヤー）", 12, "魔族", 2, 46, 108901, 18, 0, "B", 163, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ（バレンタイン）", 30, "魔族", 13, 43, 109001, 16, 0, "B", 154, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（バレンタイン）", 24, "ヒューマン", 3, 54, 109101, 18, 0, "O", 168, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "英霊と契約を結んだマナリアの天才王女", "日笠陽子", "アン", 1, "ヒューマン", "", 55, 109201, 17, 0, "AB", 156, "読書", "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "マナリア魔法学院の新入生", "こやまきみこ", "ルゥ", 4, "ヒューマン", "", 45, 109301, 16, 0, "O", 144, "食べること、眠ること", "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "人を超越した力を有す心優しい竜姫", "福原綾香", "グレア", 3, "半人半竜", "", 67, 109401, 17, 0, "B", 167, "ピアノ", "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（オーエド）", 19, "ヒューマン", 15, 49, 109501, 18, 0, "AB", 157, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン（オーエド）", 31, "ヒューマン", 15, 51, 109601, 16, 0, "O", 163, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "鬼がかりの万能妹メイド", "水瀬いのり", "レム", 2, "鬼族", "", "??", 109701, 17, 0, "?", 154, "演劇鑑賞、詩文", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "毒舌系鬼姉メイド", "村川梨衣", "ラム", 2, "鬼族", "", "??", 109801, 17, 0, "?", 154, "読書", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "銀髪のおっとりハーフエルフ", "高橋李依", "エミリア", 23, "ハーフエルフ", "", "??", 109901, "??", 0, "?", 164, "パックの毛繕い、勉強", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ（サマー）", 10, "魔族", 14, 48, 110001, 17, 0, "O", 167, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "多くの男性を魅了する無垢な女教師", "伊藤静", "イオ（サマー）", 14, "魔族", 14, 52, 110101, 23, 0, "B", 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ（サマー）", 3, "魔族", 14, 22, 110201, 11, 0, "A", 120, "ファッション誌鑑賞、コスメ集め", "", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（サマー）", 4, "エルフ", 9, 43, 110301, 17, 0, "A", 156, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "男勝りで情に厚いワイルド娘", "小松未可子", "マコト（サマー）", 9, "獣人族", 10, 54, 110401, 17, 0, "O", 168, "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "カオリ（サマー）", 7, "獣人族", 10, 53, 110501, 17, 0, "A", 158, "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "マホマホ王国のプリンセス", "内田真礼", "マホ（サマー）", 22, "獣人族", 10, 42, 110601, 16, 0, "O", 155, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）");
