INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ（ハロウィン）", 3, "獣人族", 5, 21, 111301, 10, 0, "O", 117, "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "リトルリリカル");
