INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "いつも元気な腹ペコ少女", "M・A・O", "ぺコリーヌ（ニューイヤー）", 31, "ヒューマン", 1, 46, 111801, 17, 0, "O", 156, "食べ歩き、料理", "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（ニューイヤー）", 11, "エルフ", 1, 35, 111901, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（ニューイヤー）", 2, "獣人族", 1, 39, 112001, 14, 0, "A", 152, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "お嬢さまのためにがんばるドジっ娘メイド", "悠木碧", "スズメ（ニューイヤー）", 12, "ヒューマン", 9, 43, 112101, 15, 0, "O", 154, "ご奉仕", "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ（マジカル）", 3, "獣人族", 10, 41, 112201, 15, 0, "AB", 152, "読書、推理", "", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "読書が趣味の病弱少女", "小清水亜美", "シオリ（マジカル）", 3, "獣人族", 11, 40, 112301, 14, 0, "A", 153, "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）");
