INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "遊びと睡眠が何より大事なぐうたら娘", "小岩井ことり", "リン（レンジャー）", 1, "獣人族", 11, 42, 112701, 17, 0, "B", 144, "あんパン", "", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル（レンジャー）", 3, "ヒューマン", 11, 35, 112801, 20, 0, "B", 142, "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ（ワンダー）", 25, "ヒューマン", 3, 44, 112901, 15, 0, "A", 156, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ（ワンダー）", 7, "エルフ", 15, 43, 113001, 16, 0, "O", 155, "観察", "", "ヴァイスフリューゲル　ランドソル支部");
