INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ（サマー）", 5, "魔族", 13, 45, 113201, 17, 0, "A", 159, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "オタク全開な魔法少女", "佳村はるか", "ナナカ（サマー）", 21, "魔族", 13, 55, 113301, 18, 0, "O", 166, "読書、魔法", "", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ（サマー）", 24, "エルフ", 6, 46, 113401, 17, 0, "A", 156, "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "ミサト（サマー）", 5, "エルフ", 6, 54, 113501, 21, 0, "O", 165, "絵本作り", "", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン（サマー）", 25, "ヒューマン", 8, 50, 113601, 25, 0, "A", 171, "格闘技、湯浴み", "", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "甘え上手なみんなの人気者", "浅倉杏美", "アカリ（エンジェル）", 22, "魔族", 7, 42, 113701, 13, 0, "O", 150, "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "人見知りであまのじゃくな女の子", "原紗友里", "ヨリ（エンジェル）", 22, "魔族", 7, 40, 113801, 13, 0, "O", 150, "ゲーム全般", "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ（ハロウィン）", 7, "ヒューマン", 4, 45, 113901, 14, 0, "AB", 153, "裁縫", "", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（ハロウィン）", 12, "魔族", 2, 46, 114001, 18, 0, "B", 163, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "ヒーローに憧れる騎士見習いの少女", "下田麻美", "マツリ（ハロウィン）", 25, "獣人族", 8, 40, 114101, 12, 0, "O", 146, "ヒーローごっこ", "", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ（マジカル）", 28, "ヒューマン", 15, 33, 114201, 17, 0, "A", 140, "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "義理堅くてからかい好きな剣術少女", "茅原実里", "トモ（マジカル）", 11, "ヒューマン", 8, 43, 114301, 13, 0, "A", 149, "剣術、年長者をからかう", "", "王宮騎士団（NIGHTMARE）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "アキノ（クリスマス）", 12, "ヒューマン", 12, 45, 114401, 18, 0, "AB", 157, "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（クリスマス）", 4, "エルフ", 9, 43, 114501, 17, 0, "A", 156, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "純情でほっとけない大人の女性", "今井麻美", "ユカリ（クリスマス）", 16, "エルフ", 12, 55, 114601, 22, 0, "A", 164, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "さまよえる謎の少女", "潘めぐみ", "ムイミ（ニューイヤー）", 11, "ヒューマン", "", 40, 114701, 16, 0, "O", 148, "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "研究所に隠れ住む物静かなお姉さん", "井口裕香", "ネネカ（ニューイヤー）", 24, "エルフ", "", "??", 115001, 24, 0, "O", 149, "物真似、芸術鑑賞", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（儀装束）", 11, "エルフ", 1, 35, 115501, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（儀装束）", 5, "ヒューマン", 2, 47, 115601, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ（サマー）", 3, "獣人族", 10, 41, 115701, 15, 0, "AB", 152, "読書、推理", "", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "乙女チックなもふもふアニマル", "徳井青空", "リマ（シンデレラ）", 14, "獣人族", 11, 100, 115801, 17, 0, "A", 150, "毛繕い、お喋り", "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "男勝りで情に厚いワイルド娘", "小松未可子", "マコト（シンデレラ）", 9, "獣人族", 10, 54, 115901, 17, 0, "O", 168, "お菓子作り", "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "マホマホ王国のプリンセス", "内田真礼", "マホ（シンデレラ）", 22, "獣人族", 10, 42, 116001, 16, 0, "O", 155, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "ダウンタウン育ちのダウナー系エルフ", "種﨑敦美", "クロエ（聖学祭）", 7, "エルフ", 16, 42, 116201, 17, 0, "O", 154, "ダーツ", "", "聖テレサ女学院（なかよし部）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "自由奔放ナチュラル無礼な現代っ子", "佐倉綾音", "チエル（聖学祭）", 15, "ヒューマン", 16, 46, 116301, 16, 0, "O", 156, "ダンス、カラオケ", "", "聖テレサ女学院（なかよし部）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "書庫に眠れる小さな賢人", "小原好美", "ユニ（聖学祭）", 28, "ヒューマン", 16, 36, 116401, 18, 0, "O", 142, "読書", "", "聖テレサ女学院（なかよし部）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "口が達者なヘタレドラゴン", "藤田茜", "イノリ（タイムトラベル）", 29, "ドラゴン族", 17, "???", 116501, 13, 0, "AB", 145, "ゲーム", "", "ドラゴンズネスト");
