INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ（作業服）", 6, "エルフ", 6, 44, 116701, 13, 0, "AB", 158, "友達作りのイメトレ", "", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（作業服）", 1, "獣人族", 12, 48, 116801, 19, 0, "AB", 158, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "仕事も私事も効率優先な傭兵少女", "田所あずさ", "ミフユ（作業服）", 11, "ヒューマン", 12, 49, 116901, 20, 0, "O", 163, "傭兵などのアルバイト", "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "運命の相手に一途すぎる乙女", "橋本ちなみ", "エリコ（サマー）", 30, "魔族", 13, 43, 117001, 16, 0, "B", 154, "実験、裁縫、料理", "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（サマー）", 24, "ヒューマン", 3, 54, 117101, 18, 0, "O", 168, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "歌って踊れる大人気アイドル", "日笠陽子", "ノゾミ（サマー）", 24, "ヒューマン", 4, 40, 117201, 17, 0, "B", 157, "舞台鑑賞、ダンス", "", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "人々を守るために歌う、唱喚士の少女", "福原綾香", "チカ（サマー）", 3, "ヒューマン", 4, 46, 117301, 17, 0, "O", 163, "各種楽器", "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "ファッション大好きなキュートガール", "木戸衣吹", "ツムギ（サマー）", 7, "ヒューマン", 4, 45, 117401, 14, 0, "AB", 153, "裁縫", "", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "実験が趣味の危険な科学者", "三石琴乃", "ミツキ（オーエド）", 7, "ヒューマン", 13, 53, 117501, 27, 0, "A", 166, "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "ボクは誰よりも美しい", "大空直美", "ユキ（オーエド）", 10, "エルフ", 15, 40, 117601, 14, 0, "AB", 150, "鏡で自分を見ること", "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "いつでも「なんくるないさ～」な天然娘", "高森奈津美", "カオリ（ハロウィン）", 7, "獣人族", 10, 53, 117701, 17, 0, "A", 158, "踊り、空手", "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン（ハロウィン）", 31, "ヒューマン", 15, 51, 117801, 16, 0, "O", 163, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ（ハロウィン）", 10, "魔族", 14, 48, 117901, 17, 0, "O", 167, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "忠義に目覚めた女商人", "Lynn", "クレジッタ", 19, "ヒューマン", 18, 57, 118001, 26, 0, "A", 160, "お金を数えること、悪だくみ", "", "リッチモンド商工会");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "静寂を求め歌う陰気少女", "原田彩楓", "ランファ", 28, "魔族", 19, 53, 118101, 20, 0, "O", 165, "歌、読書、詩を書くこと", "", "レイジ・レギオン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "明朗快活、なれど破滅に流るる溌溂少女", "鬼頭明里", "ミソラ", 2, "ヒューマン", 19, "??", 118201, 16, 0, "A", 159, "特に無し", "", "レイジ・レギオン");
