INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("?", "幻霧に戯れる悪戯好きなガイド妖精", "相坂優歌", "ネビア", "?", "？？？", "", "???", 118601, "??", 0, "?", "???", "悪戯をすること", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "多くの男性を魅了する無垢な女教師", "伊藤静", "イオ（ノワール）", 14, "魔族", 14, 52, 119001, 23, 0, "B", 162, "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（ノワール）", 19, "ヒューマン", 15, 49, 119101, 18, 0, "AB", 157, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "みんなを笑顔にするお笑い牧場主", "新田恵海", "マヒル（クリスマス）", 3, "ヒューマン", 11, 35, 119201, 20, 0, "B", 142, "漫才", "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ（クリスマス）", 25, "ヒューマン", 3, 44, 119301, 15, 0, "A", 156, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "プリン大好きゴースト娘", "雨宮天", "ミヤコ（クリスマス）", 23, "魔族", 7, 32, 119901, 14, 0, "B", 130, "プリンを食べること", "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（ノワール）", 24, "ヒューマン", 3, 54, 120001, 18, 0, "O", 168, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス");
