INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（オーバーロード）", 2, "獣人族", 1, 39, 121101, 14, 0, "A", 152, "猫と遊ぶ", "", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "秘密結社ラビリンスの『迷宮女王』", "沢城みゆき", "ラビリスタ（オーバーロード）", 25, "ヒューマン", 3, "??", 121201, 25, 0, "AB", 160, "人間観察", "", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "泣き虫で臆病な守ってあげたい女の子", "植田佳奈", "クルミ（ステージ）", 9, "ヒューマン", 9, 40, 121301, 12, 0, "B", 150, "観劇、おままごと", "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "ちょっとおませな恋に恋する女の子", "久野美咲", "ミサキ（ステージ）", 3, "魔族", 14, 22, 121401, 11, 0, "A", 120, "ファッション誌鑑賞、コスメ集め", "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "どこまでも一途に慕う、純情乙女", "大関英里", "アユミ（怪盗）", 7, "エルフ", 15, 43, 121501, 16, 0, "O", 155, "観察", "", "ヴァイスフリューゲル　ランドソル支部");
