INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "前世を信じる中二病患者、「疾風の冥姫」", "髙野麻美", "アンナ（パイレーツ）", 5, "魔族", 13, 45, 121901, 17, 0, "A", 159, "小説執筆", "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "占いが得意な霊能少女", "大坪由佳", "シノブ（パイレーツ）", 22, "魔族", 7, 42, 122001, 18, 0, "AB", 157, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "「友達」に憧れる、エルフの森の女の子", "花澤香菜", "アオイ（キャンプ）", 6, "エルフ", 6, 44, 122101, 13, 0, "AB", 158, "友達作りのイメトレ", "", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "純情でほっとけない大人の女性", "今井麻美", "ユカリ（キャンプ）", 16, "エルフ", 12, 55, 122201, 22, 0, "A", 164, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "けんぞくのご主人様", "釘宮理恵", "ヴァンピィ", 6, "魔族", "", 41, 122301, "??", 0, "AB", 149, "お散歩、お料理", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（サマー）", 27, "獣人族", 2, 44, 122401, 16, 0, "A", 155, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（サマー）", 12, "魔族", 2, 46, 122501, 18, 0, "B", 163, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（サマー）", 5, "ヒューマン", 2, 47, 122601, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "礼儀正しくしっかり者のちびっ子優等生", "小倉唯", "キョウカ（サマー）", 2, "エルフ", 5, 21, 122701, 8, 0, "A", 118, "お勉強", "", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "探検好きのイタズラっ子", "諸星すみれ", "ミソギ（サマー）", 10, "ヒューマン", 5, 27, 122801, 9, 0, "O", 128, "いたずら、探検", "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "お歌もにんじんも、ウサギさんも大好き♪", "日高里菜", "ミミ（サマー）", 3, "獣人族", 5, 21, 122901, 10, 0, "O", 117, "かわいいもの集め", "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "リトルリリカル");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("?", "新たな姿で騎士の冒険を支え続ける妖精", "相坂優歌", "アメス", "?", "？？？", "", "???", 123001, "??", 0, "?", 150, "？？？", "", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "マホマホ王国のプリンセス", "内田真礼", "マホ（エクスプローラー）", 22, "獣人族", 10, 42, 123101, 16, 0, "O", 155, "空想、ぬいぐるみ集め", "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "ぷうきちといつも一緒！", "芹澤優", "アヤネ（エクスプローラー）", 10, "ヒューマン", 9, 38, 123201, 14, 0, "B", 148, "屋内でできる遊び", "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "サレンディア救護院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "ショタ大好き♪　ギャル系スライム娘", "和氣あず未", "ネア", 13, "魔族？", 19, 55, 123301, 19, 0, "B", 157, "可愛いショタと遊ぶ、買い物", "", "レイジ・レギオン");
