INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (2, "傍若無人な王宮騎士団副団長", "たかはし智秋", "クリスティーナ（ワイルド）", 7, "ヒューマン", 8, "??", 123801, 27, 0, "O", 165, "強敵との闘争", "", "王宮騎士団（NIGHTMARE）");
