INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "甘え上手なみんなの人気者", "浅倉杏美", "アカリ（クリスマス）", 22, "魔族", 7, 42, 124001, 13, 0, "O", 150, "サックス", "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "悪魔偽王国軍（ディアボロス）");
