INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "素顔を見せない冷静沈着な女性騎士", "川澄綾子", "ジュン（クリスマス）", 25, "ヒューマン", 8, 50, 124201, 25, 0, "A", 171, "格闘技、湯浴み", "", "王宮騎士団（NIGHTMARE）");
