INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "母性溢れる優しいみんなの「ミサト先生」", "國府田マリ子", "ミサト（ニューイヤー）", 5, "エルフ", 6, 54, 124601, 21, 0, "O", 165, "絵本作り", "", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "実験が趣味の危険な科学者", "三石琴乃", "ミツキ（ニューイヤー）", 7, "ヒューマン", 13, 53, 124701, 27, 0, "A", 166, "研究、実験", "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "トワイライトキャラバン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "歌って踊れる大人気アイドル", "日笠陽子", "ノゾミ（リベレイター）", 24, "ヒューマン", 4, 40, 124801, 17, 0, "B", 157, "舞台鑑賞、ダンス", "", "カルミナ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (6, "拳で語る喧嘩屋ドラゴン少女", "小市眞琴", "カヤ（リベレイター）", 25, "ドラゴン族", 17, "???", 124901, 16, 0, "B", 156, "格闘技", "", "ドラゴンズネスト");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "さまよえる謎の少女", "潘めぐみ", "ムイミ（リベレイター）", 11, "ヒューマン", "", 40, 125001, 16, 0, "O", 148, "冒険、思い出話", "いいんだ、アタシは……独りでも。大丈夫だから、もう慣れたからさぁ", "？？？");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "弱きを助け強きをくじく猫娘", "沼倉愛美", "タマキ（カフェ）", 1, "獣人族", 12, 48, 125101, 19, 0, "AB", 158, "猫とたわむれること", "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "見た目も中身もお子ちゃまな異国の軍人", "辻あゆみ", "モニカ（カフェ）", 28, "ヒューマン", 15, 33, 125201, 17, 0, "A", 140, "お菓子屋通い", "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（レンジャー）", 11, "エルフ", 1, 35, 125301, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "読書が趣味の病弱少女", "小清水亜美", "シオリ（レンジャー）", 3, "獣人族", 11, 40, 125401, 14, 0, "A", 153, "読書、お散歩", "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "牧場（エリザベスパーク）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "空への冒険を夢見る騎空士の少女", "金元寿子", "ジータ（ウォーロック）", 10, "ヒューマン", "", 45, 125501, 17, 0, "O", 156, "冒険、おしゃべり", "", "？？？");
