INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "正義の魂を受け継ぐ、爆食系天然天才娘", "高尾奏音", "プレシア（フォールン）", 1, "獣人族", 20, 34, 126101, 10, 0, "O", 135, "ごはんをたべること", "", "アルターメイデン");
