INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "一人前の商人を目指すパワフルお嬢様", "松嵜麗", "アキノ（サマー）", 12, "ヒューマン", 12, 45, 126701, 18, 0, "AB", 157, "慈善事業", "この私とともにいる限り、\nお金に不自由はさせませんわ！", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (3, "純情でほっとけない大人の女性", "今井麻美", "ユカリ（サマー）", 16, "エルフ", 12, 55, 126801, 22, 0, "A", 164, "ウインドーショッピング", "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "メルクリウス財団");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "静寂を求め歌う陰気少女", "原田彩楓", "ランファ（サマー）", 28, "魔族", 19, 53, 126901, 20, 0, "O", 165, "歌、読書、詩を書くこと", "", "レイジ・レギオン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "妄想大好き！　ほんとは照れ屋な女の子", "長妻樹里", "クウカ（サマー）", 19, "ヒューマン", 15, 49, 127001, 18, 0, "AB", 157, "小説を読むこと", "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "ヴァイスフリューゲル　ランドソル支部");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "占いが得意な霊能少女", "大坪由佳", "シノブ（サマー）", 22, "魔族", 7, 42, 127101, 18, 0, "AB", 157, "占い", "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "悪魔偽王国軍（ディアボロス）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, "行き倒れの謎のネコミミ魔法使い", "立花理香", "キャル（編入生）", 2, "獣人族", 1, 39, 127201, 14, 0, "A", 152, "猫と遊ぶ", "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "天真爛漫で人気者のカリスマモデル", "上坂すみれ", "スズナ（編入生）", 10, "魔族", 14, 48, 127301, 17, 0, "O", 167, "ファッション", "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "ルーセント学院");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（サラサリア）", 4, "エルフ", 9, 43, 127501, 17, 0, "A", 156, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院");
