INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, "みんなのために超能力を使う眠り姫", "大橋彩香", "ハツネ（ニューイヤー）", 24, "エルフ", 6, 46, 128401, 17, 0, "A", 156, "妹と遊ぶこと、二度寝、昼寝、早寝", "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "フォレスティエ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, "頭脳明晰な美少女名探偵", "水瀬いのり", "カスミ（ニューイヤー）", 3, "獣人族", 10, 41, 128501, 15, 0, "AB", 152, "読書、推理", "", "自警団（カォン）");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（アストラル）", 27, "獣人族", 2, 44, 128701, 16, 0, "A", 155, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (1, "クールで何事にも真っ直ぐな剣士", "早見沙織", "レイ（アストラル）", 12, "魔族", 2, 46, 128801, 18, 0, "B", 163, "読書、乗馬、お茶", "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（アストラル）", 5, "ヒューマン", 2, 47, 128901, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
