INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "救護院を経営する優しい庶民派お嬢様", "堀江由衣", "サレン（ニューイヤー）", 4, "エルフ", 9, 43, 133501, 17, 0, "A", 156, "経営、お茶会", "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレンディア救護院");
