INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人助けが大好き！　前向き格闘娘", "東山奈央", "ヒヨリ（サラサリア）", 27, "獣人族", 2, 44, 135701, 16, 0, "A", 155, "人助け、応援", "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "トゥインクルウィッシュ");
