INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (7, "明朗快活、なれど破滅に流るる溌溂少女", "鬼頭明里", "ミソラ（クリスマス）", 2, "ヒューマン", 19, "??", 136301, 16, 0, "A", 159, "特に無し", "", "レイジ・レギオン");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (4, "戦闘のサポートが得意な、心優しい少女", "種田梨沙", "ユイ（クリスマス）", 5, "ヒューマン", 2, 47, 136401, 17, 0, "O", 158, "料理、人間観察", "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "トゥインクルウィッシュ");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, "お姉ちゃんがお世話してあげるからねっ！", "生天目仁美", "シズル（ニューイヤー）", 24, "ヒューマン", 3, 54, 136501, 18, 0, "O", 168, "家事全般", "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "ラビリンス");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "トーゴクの神秘、オシエテクダサイ！", "佐藤聡美", "ニノン（サマー）", 31, "ヒューマン", 15, 51, 137101, 16, 0, "O", 163, "忍法開発", "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ヴァイスフリューゲル　ランドソル支部");
