INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を想い、“進化”したガイド役", "伊藤美来", "コッコロ（嚮導幼君）", 11, "エルフ", 1, 48, 137601, 11, 0, "B", 164, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, "人懐っこくてマシンガントークな妹系少女", "阿澄佳奈", "リノ（ニューイヤー）", 25, "ヒューマン", 3, 44, 137901, 15, 0, "A", 156, "お裁縫", "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "ラビリンス");
