INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (5, "主を慕う、小さなガイド役", "伊藤美来", "コッコロ（プリンセス）", 11, "エルフ", 1, 35, 180501, 11, 0, "B", 140, "瞑想、動植物の飼育", "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", "美食殿");
